INSERT INTO `evaluari` VALUES (1,'2026-02-28 19:00:42.292059','2026-02-27','scolioza','Prezinta dureri la spate nu stiu','2733282b-1ee8-4afb-827a-aa0ff0b98f61',1,3,3,'496b7af4-d378-418d-8d5f-5647ed31d11d','INITIALA','2026-02-28 19:00:42.292059','SYSTEM','SYSTEM'),(2,'2026-03-15 17:30:46.429070','2026-03-03','scolioza','','2733282b-1ee8-4afb-827a-aa0ff0b98f61',7,3,3,'496b7af4-d378-418d-8d5f-5647ed31d11d','REEVALUARE','2026-03-16 18:23:03.286194','SYSTEM','SYSTEM'),(3,'2026-03-17 16:51:33.333250','2026-03-17','dorsalgie','','072ee168-7759-4613-96e1-226f0d7277ea',9,5,3,'496b7af4-d378-418d-8d5f-5647ed31d11d','INITIALA','2026-03-17 16:51:33.333250','SYSTEM','SYSTEM'),(4,'2026-03-05 09:35:00.000000','2026-03-05','Hernie de disc L4-L5','Postură asimetrică la nivelul umerilor și bazinului, cu rotație toracală vizibilă. Mobilitate redusă în flexia laterală stângă. Pacientul raportează disconfort ocazional în zona lombară la efort prelungit.','77d841ba-ba92-4d98-a6bd-873c58fbc440',10,10,6,'05e0f10e-2c4d-405e-abac-5ccedb83d2af','INITIALA','2026-03-05 09:35:00.000000','SYSTEM','SYSTEM'),(5,'2026-03-10 09:35:00.000000','2026-03-10','Cifoscolioză','Asimetrie scapulară evidentă. Tensiune crescută pe musculatura paravertebrală dreaptă. Necesită corectare posturală activă și stretching.','e61befe0-0110-45b7-9a31-8f433b113909',12,5,6,'f90f7761-c2ee-41f5-92fb-96c47b6567f5','INITIALA','2026-03-10 09:35:00.000000','SYSTEM','SYSTEM'),(6,'2026-03-10 09:35:00.000000','2026-02-16','Lombosciatica dreapta','Pacienta prezinta durere ascutita la flexia trunchiului. Testul Lasegue pozitiv la 45 grade. Deficit usor de forta pe flexia dorsala.','31d03fc1-1800-4a52-9817-0c6b21d78e14',17,10,6,'05e0f10e-2c4d-405e-abac-5ccedb83d2af','INITIALA','2026-03-10 09:35:00.000000','SYSTEM','SYSTEM'),(7,'2026-03-12 08:35:00.000000','2026-03-12','Tendinită ahiliană','Durere acută la palpare și la flexia dorsală a gleznei stângi. Mers antalgic ușor șchiopătat observat la intrarea în cabinet.','6da1727a-5388-4bfb-b845-d96485c61498',20,8,6,'d407ab1c-7554-456d-9726-3f5571fa8fd0','INITIALA','2026-03-12 08:35:00.000000','SYSTEM','SYSTEM'),(8,'2026-03-18 12:35:00.000000','2026-03-18','Sindrom patelofemural','Crepitus palpabil la nivelul genunchiului drept în timpul genuflexiunilor. Slăbiciune marcată a vastului medial (VMO).','6c400be7-84b0-40f9-8854-b90e6c8358d9',22,10,6,'cb3ac7f5-4730-44cf-a053-d17f451f4b02','INITIALA','2026-03-18 12:35:00.000000','SYSTEM','SYSTEM'),(9,'2026-03-20 10:35:00.000000','2026-03-20','Fasciită plantară','Durere matinală severă declarată la primii pași. Retracție semnificativă pe lanțul fascial posterior. Fascia de la piciorul drept îngroșată la palpare.','487da990-f8ed-437f-b5d9-e9e2f5aef199',24,6,6,'69f7e2ae-39c0-4506-8558-d782493821a0','INITIALA','2026-03-20 10:35:00.000000','SYSTEM','SYSTEM'),(10,'2026-03-23 11:35:00.000000','2026-03-23','Cervicalgie miotensivă','Contractură marcată a mușchiului trapez bilateral. Tensiune ridicată pe musculatura suboccipitală, cel mai probabil indusă de lucrul prelungit la birou cu postură incorectă.','a2351fcd-9e0c-4ebc-b6fb-2530c9892556',25,5,7,'51abc54c-0c2f-4f0a-aead-bdaa9627661e','INITIALA','2026-03-23 11:35:00.000000','SYSTEM','SYSTEM'),(11,'2026-03-19 14:30:00.000000','2026-03-19','Lombosciatică stângă','Durere lombară cu iradiere pe membrul inferior stâng. Test Lasegue pozitiv la 50 de grade. Recomand începerea exercițiilor de decompresie și tonifiere progresivă, folosind rezistență elastică.','5f89ace3-454d-486a-accd-986caa20d84a',37,10,6,'05e0f10e-2c4d-405e-abac-5ccedb83d2af','INITIALA','2026-03-19 14:30:00.000000','SYSTEM','SYSTEM'),(12,'2026-02-16 09:40:00.000000','2026-02-16','Entorsă gleznă grad II','Edem moderat la nivelul maleolei externe. Mobilitate redusă în flexie dorsală. Pacienta a început recuperarea după 3 săptămâni de imobilizare.','b6f3d53a-f2d3-4e2b-b531-d1463a88ef70',38,10,6,'05e0f10e-2c4d-405e-abac-5ccedb83d2af','INITIALA','2026-02-16 09:40:00.000000','SYSTEM','SYSTEM'),(13,'2026-02-19 14:40:00.000000','2026-02-19','Cifoză dorsală','Tensiune pe musculatura pectorală. Spate rotund vizibil în repaus. Pacientul nu are istoric sportiv și lucrează foarte mult la birou.','00179244-a86e-4ade-8e22-3d70af6de57d',51,7,6,'05e0f10e-2c4d-405e-abac-5ccedb83d2af','INITIALA','2026-03-25 18:31:04.488551','SYSTEM','SYSTEM'),(14,'2026-03-25 18:42:57.750882','2026-03-25','Cifoză dorsală','Pacientul este cooperant și a respectat parțial recomandările de exerciții pentru acasă. Se menține tendința de poziție cifotică în perioadele prelungite de lucru la birou.','00179244-a86e-4ade-8e22-3d70af6de57d',66,4,6,'05e0f10e-2c4d-405e-abac-5ccedb83d2af','REEVALUARE','2026-03-25 18:42:57.750882','SYSTEM','SYSTEM'),(21,'2026-06-12 10:35:00.000000','2026-06-12','Cervicalgie miotensivă - Ameliorată rapid','Mobilitatea cervicala este complet restaurata, fara dureri la miscarile de rotatie. Spasmele pe trapez s-au redus considerabil. Recomand 4 sedinte individuale de stabilizare posturala pentru preventie.','a2351fcd-9e0c-4ebc-b6fb-2530c9892556',107,4,6,'51abc54c-0c2f-4f0a-aead-bdaa9627661e','REEVALUARE','2026-06-12 10:35:00.000000','51abc54c-0c2f-4f0a-aead-bdaa9627661e','51abc54c-0c2f-4f0a-aead-bdaa9627661e'),(22,'2026-06-01 09:35:00.000000','2026-06-01','Lombalgie cronică','Pacienta acuza dureri lombare difuze, accentuate dupa perioade lungi de sezut la birou. Mobilitatea coloanei este redusa in flexie. Forta musculara abdominala este scazuta. Recomand un program de 6 sedinte individuale axate pe decompresie si tonifierea musculaturii paravertebrale.','de85c053-a583-4219-8fe9-5afd66c0e812',113,6,6,'d407ab1c-7554-456d-9726-3f5571fa8fd0','INITIALA','2026-06-01 09:35:00.000000','d407ab1c-7554-456d-9726-3f5571fa8fd0','d407ab1c-7554-456d-9726-3f5571fa8fd0'),(23,'2026-06-17 09:35:00.000000','2026-06-17','Lombalgie cronică - Ameliorată','Durerea a scazut semnificativ (de la 7 la 1). Controlul motor al bazinului s-a imbunatatit. Recomand continuarea cu 5 sedinte de gimnastica profilactica pentru mentinere si educatie posturala.','de85c053-a583-4219-8fe9-5afd66c0e812',120,5,8,'d407ab1c-7554-456d-9726-3f5571fa8fd0','REEVALUARE','2026-06-17 09:35:00.000000','d407ab1c-7554-456d-9726-3f5571fa8fd0','d407ab1c-7554-456d-9726-3f5571fa8fd0'),(24,'2026-06-01 11:35:00.000000','2026-06-01','Hernie de disc L5-S1 (post-op)','Pacienta se prezinta la 6 saptamani post-operator. Prezinta frica de miscare (kineziofobie), rigiditate lombara si deficit de forta pe membrul inferior stang. Se recomanda 4 sedinte de recuperare post-operatorie focusate pe decompresie blanda si recastigarea mobilitatii neuro-musculare.','8bd48465-32ec-413b-9985-9a57a03a3d88',126,4,7,'05e0f10e-2c4d-405e-abac-5ccedb83d2af','INITIALA','2026-06-01 11:35:00.000000','05e0f10e-2c4d-405e-abac-5ccedb83d2af','05e0f10e-2c4d-405e-abac-5ccedb83d2af'),(25,'2026-06-09 11:35:00.000000','2026-06-09','Hernie de disc L5-S1 (post-op) - Evoluție pozitivă','Mobilitatea generala s-a imbunatatit. Kineziofobia s-a redus substantial. Pacienta executa tranzitii posturale corecte. Recomand un nou program de 4 sedinte individuale de kinetoterapie pentru stabilizare activa.','8bd48465-32ec-413b-9985-9a57a03a3d88',131,4,6,'05e0f10e-2c4d-405e-abac-5ccedb83d2af','REEVALUARE','2026-06-09 11:35:00.000000','05e0f10e-2c4d-405e-abac-5ccedb83d2af','05e0f10e-2c4d-405e-abac-5ccedb83d2af'),(26,'2026-06-10 15:35:00.000000','2026-06-10','Cervicalgie miotensivă - Ameliorată','Control postural optim. Forta paravertebrala cervicala refacuta complet. Pacientul incepe planul profilactic de mentinere (3 sedinte recomandate).','00179244-a86e-4ade-8e22-3d70af6de57d',144,3,8,'05e0f10e-2c4d-405e-abac-5ccedb83d2af','REEVALUARE','2026-06-10 15:35:00.000000','05e0f10e-2c4d-405e-abac-5ccedb83d2af','05e0f10e-2c4d-405e-abac-5ccedb83d2af'),(27,'2026-06-02 10:35:00.000000','2026-06-02','Entorsă gleznă grad II - Mobilitate redusă','Stabilitatea gleznei a scazut in perioada de inactivitate. Mobilitatea in flexie dorsala este limitata si insotita de jena la 15 grade. Se recomanda 5 sedinte de kinetoterapie pentru proprioceptie.','b6f3d53a-f2d3-4e2b-b531-d1463a88ef70',150,5,6,'05e0f10e-2c4d-405e-abac-5ccedb83d2af','REEVALUARE','2026-06-02 10:35:00.000000','05e0f10e-2c4d-405e-abac-5ccedb83d2af','05e0f10e-2c4d-405e-abac-5ccedb83d2af'),(30,'2026-06-08 09:35:00.000000','2026-06-08','Cervicobrahialgie stângă','Contractură musculară la nivelul trapezului superior stâng și musculaturii scalene. Mobilitate cervicală redusă în rotație. Recomand un plan de 8 ședințe de fizioterapie.','5ff54c13-8ec1-40b3-b147-bbf2ad48fb86',212,8,6,'69f7e2ae-39c0-4506-8558-d782493821a0','INITIALA','2026-06-08 09:35:00.000000','69f7e2ae-39c0-4506-8558-d782493821a0','69f7e2ae-39c0-4506-8558-d782493821a0'),(31,'2026-06-08 08:35:00.000000','2026-06-08','Scolioză toraco-lombară','Asimetrie de umeri și bazin, rotație vertebrală vizibilă la testul Adams. Recomand un plan intens de kinetoterapie individuală (10 ședințe) axat pe metoda Schroth.','ac0ef5eb-34df-4a8c-8f4a-e879428aed2d',215,10,6,'d407ab1c-7554-456d-9726-3f5571fa8fd0','INITIALA','2026-06-08 08:35:00.000000','d407ab1c-7554-456d-9726-3f5571fa8fd0','d407ab1c-7554-456d-9726-3f5571fa8fd0'),(32,'2026-06-08 12:35:00.000000','2026-06-08','Tendinită rotuliană dreaptă','Durere localizată la polul inferior al rotulei drepte, exacerbată la palparea tendonului rotulian. Mobilitate normală. Recomand 6 ședințe de recuperare.','235aa647-1c6c-479f-aa26-011539b51b73',227,6,6,'496b7af4-d378-418d-8d5f-5647ed31d11d','INITIALA','2026-06-08 12:35:00.000000','496b7af4-d378-418d-8d5f-5647ed31d11d','496b7af4-d378-418d-8d5f-5647ed31d11d'),(33,'2026-06-08 13:35:00.000000','2026-06-08','Cifoză dorsală accentuată','Postură cifotică rigidă, rigiditate în hiperextensie dorsală. Spasm muscular pe erectorii spinali. Recomand 8 ședințe de reeducare posturală.','9f90d398-f030-4ce4-bfee-033758993378',230,8,6,'496b7af4-d378-418d-8d5f-5647ed31d11d','INITIALA','2026-06-08 13:35:00.000000','496b7af4-d378-418d-8d5f-5647ed31d11d','496b7af4-d378-418d-8d5f-5647ed31d11d'),(34,'2026-03-30 09:35:00.000000','2026-03-30','Cervicalgie miotensiva - Ameliorata','Pacienta a finalizat cele 10 sedinte prescrise. Mobilitatea cervicala si postura generala s-au imbunatatit semnificativ. Se recomanda un program de mentinere de 5 sedinte individuale de kinetoterapie.','31d03fc1-1800-4a52-9817-0c6b21d78e14',36,5,6,'05e0f10e-2c4d-405e-abac-5ccedb83d2af','REEVALUARE','2026-03-30 09:35:00.000000','SYSTEM','SYSTEM'),(35,'2026-06-15 13:30:00.000000','2026-06-15','Lombosciatică stângă','Stare ameliorată, mobilitate crescută la nivel lombar. Se continuă planul terapeutic cu încă 6 ședințe de tonifiere musculară profundă.','31d03fc1-1800-4a52-9817-0c6b21d78e14',165,6,6,'05e0f10e-2c4d-405e-abac-5ccedb83d2af','REEVALUARE','2026-06-15 13:30:00.000000','SYSTEM','SYSTEM'),(36,'2026-06-22 10:30:00.000000','2026-06-22','Hernie de disc L5-S1','Evoluție favorabilă. Se constată creșterea mobilității articulare. Se recomandă continuarea cu un nou set de 5 ședințe pentru consolidarea rezultatelor.','b6f3d53a-f2d3-4e2b-b531-d1463a88ef70',156,5,6,'05e0f10e-2c4d-405e-abac-5ccedb83d2af','REEVALUARE','2026-06-22 10:30:00.000000','SYSTEM','SYSTEM'),(37,'2026-06-22 09:30:00.000000','2026-06-22','Sindrom postural cronic','Progres semnificativ. Aliniament postural optim în poziție statică. Se recomandă încă 4 ședințe de gimnastică profilactică pentru menținerea tonusului și a posturii corecte.','00179244-a86e-4ade-8e22-3d70af6de57d',148,4,8,'05e0f10e-2c4d-405e-abac-5ccedb83d2af','REEVALUARE','2026-06-22 09:30:00.000000','SYSTEM','SYSTEM');
