INSERT INTO `evolutii` VALUES (1,'2026-02-28 19:01:02.181851','abcdefghijklmn','2733282b-1ee8-4afb-827a-aa0ff0b98f61','496b7af4-d378-418d-8d5f-5647ed31d11d','2026-02-28 19:01:02.181851','SYSTEM','SYSTEM'),(2,'2026-03-16 18:24:46.152991','abc','2733282b-1ee8-4afb-827a-aa0ff0b98f61','496b7af4-d378-418d-8d5f-5647ed31d11d','2026-03-16 18:24:46.152991','SYSTEM','SYSTEM'),(3,'2026-03-20 11:00:00.000000','A efectuat exercițiile corect, dar are dificultăți la menținerea posturii. Necesită mai multă atenție pe controlul trunchiului și respirație diafragmatică în timpul efortului.','77d841ba-ba92-4d98-a6bd-873c58fbc440','51abc54c-0c2f-4f0a-aead-bdaa9627661e','2026-03-20 11:00:00.000000','SYSTEM','SYSTEM'),(4,'2026-03-20 15:00:00.000000','Toleranță crescută la exercițiile cu rezistență elastică. Am progresat la lucrul cu greutăți mici. Durerea iradiantă pe picior a scăzut semnificativ.','5f89ace3-454d-486a-accd-986caa20d84a','05e0f10e-2c4d-405e-abac-5ccedb83d2af','2026-03-19 15:00:00.000000','SYSTEM','SYSTEM'),(5,'2026-03-02 10:00:00.000000','Mobilitatea lombara s-a imbunatatit usor dupa exercitiile de decomprimare. Vom insista pe stretching activ.','31d03fc1-1800-4a52-9817-0c6b21d78e14','05e0f10e-2c4d-405e-abac-5ccedb83d2af','2026-03-17 11:00:00.000000','SYSTEM','SYSTEM'),(6,'2026-03-19 10:00:00.000000','Am început protocolul de exerciții excentrice. Pacientul tolerează bine sarcina pe tendon, durerea raportată în timpul execuției este minimă.','6da1727a-5388-4bfb-b845-d96485c61498','d407ab1c-7554-456d-9726-3f5571fa8fd0','2026-03-19 10:00:00.000000','SYSTEM','SYSTEM'),(7,'2026-03-18 12:40:00.000000','Pacient deschis, înțelege importanța activării gluteilor. Am stabilit exerciții simple de făcut și acasă zilnic.','6c400be7-84b0-40f9-8854-b90e6c8358d9','cb3ac7f5-4730-44cf-a053-d17f451f4b02','2026-03-18 12:40:00.000000','SYSTEM','SYSTEM'),(8,'2026-03-16 10:00:00.000000','Pacienta a executat corect exercitiile de stabilizare lombara (Bird-Dog). Am crescut usor rezistenta. Progres vizibil pe mobilitate.','31d03fc1-1800-4a52-9817-0c6b21d78e14','05e0f10e-2c4d-405e-abac-5ccedb83d2af','2026-03-24 10:05:00.000000','SYSTEM','SYSTEM'),(9,'2026-03-23 10:00:00.000000','Aproape de recuperare completa a mobilitatii. Pregatim planul de intretinere pe termen lung pentru acasa.','31d03fc1-1800-4a52-9817-0c6b21d78e14','05e0f10e-2c4d-405e-abac-5ccedb83d2af','2026-03-23 10:00:00.000000','SYSTEM','SYSTEM'),(10,'2026-03-03 11:00:00.000000','Edemul a dispărut complet. Mersul pe plan drept s-a îmbunătățit, dar încă are ușoară instabilitate la coborârea scărilor.','b6f3d53a-f2d3-4e2b-b531-d1463a88ef70','05e0f10e-2c4d-405e-abac-5ccedb83d2af','2026-03-03 11:00:00.000000','SYSTEM','SYSTEM'),(11,'2026-03-17 11:00:00.000000','Am introdus exerciții pe placa de propriocepție. Pacienta reacționează foarte bine la stimulii de dezechilibru ușor.','b6f3d53a-f2d3-4e2b-b531-d1463a88ef70','05e0f10e-2c4d-405e-abac-5ccedb83d2af','2026-03-17 11:00:00.000000','SYSTEM','SYSTEM'),(12,'2026-03-06 16:00:00.000000','Înțelege greu activarea romboizilor. Compensăm prin exerciții ghidate tactil. Toleranță scăzută la efort.','00179244-a86e-4ade-8e22-3d70af6de57d','05e0f10e-2c4d-405e-abac-5ccedb83d2af','2026-03-06 16:00:00.000000','SYSTEM','SYSTEM'),(13,'2026-03-20 16:00:00.000000','Postura începe să se corecteze. Pacientul relatează că resimte oboseală musculară mai puțin la birou. Continuăm pe tonifiere.','00179244-a86e-4ade-8e22-3d70af6de57d','05e0f10e-2c4d-405e-abac-5ccedb83d2af','2026-03-20 16:00:00.000000','SYSTEM','SYSTEM'),(21,'2026-06-01 11:05:00.000000','Prima sedinta de kinetoterapie. Am lucrat pe mobilitate articulara pasiva si stretching bland. Pacienta are o usoara teama de durere, dar raspunde bine la indicatii.','a2351fcd-9e0c-4ebc-b6fb-2530c9892556','51abc54c-0c2f-4f0a-aead-bdaa9627661e','2026-06-01 11:05:00.000000','51abc54c-0c2f-4f0a-aead-bdaa9627661e','51abc54c-0c2f-4f0a-aead-bdaa9627661e'),(22,'2026-06-03 11:05:00.000000','Am introdus exercitii izometrice pentru stabilizare paravertebrala si cervicala. Contracturile musculare din zona omoplatilor incep sa se relaxeze.','a2351fcd-9e0c-4ebc-b6fb-2530c9892556','51abc54c-0c2f-4f0a-aead-bdaa9627661e','2026-06-03 11:05:00.000000','51abc54c-0c2f-4f0a-aead-bdaa9627661e','51abc54c-0c2f-4f0a-aead-bdaa9627661e'),(23,'2026-06-05 11:05:00.000000','Mobilitatea cervicala a progresat. Pacienta raporteaza ca durerea matinala a scazut in intensitate. Am crescut numarul de repetari la exercitiile posturale.','a2351fcd-9e0c-4ebc-b6fb-2530c9892556','51abc54c-0c2f-4f0a-aead-bdaa9627661e','2026-06-05 11:05:00.000000','51abc54c-0c2f-4f0a-aead-bdaa9627661e','51abc54c-0c2f-4f0a-aead-bdaa9627661e'),(24,'2026-06-09 11:05:00.000000','Sedinta reprogramata. Pacienta a fost obosita, dar am putut efectua programul complet. Control postural bun la oglinda.','a2351fcd-9e0c-4ebc-b6fb-2530c9892556','51abc54c-0c2f-4f0a-aead-bdaa9627661e','2026-06-09 11:05:00.000000','51abc54c-0c2f-4f0a-aead-bdaa9627661e','51abc54c-0c2f-4f0a-aead-bdaa9627661e'),(25,'2026-06-10 11:05:00.000000','Sedinta 5 finalizata. Cota prescribed atinsa. Pacienta are o postura mult imbunatatita, durerea este aproape absenta. Urmeaza reevaluarea programata.','a2351fcd-9e0c-4ebc-b6fb-2530c9892556','51abc54c-0c2f-4f0a-aead-bdaa9627661e','2026-06-10 11:05:00.000000','51abc54c-0c2f-4f0a-aead-bdaa9627661e','51abc54c-0c2f-4f0a-aead-bdaa9627661e'),(26,'2026-07-06 10:55:00.000000','Inceputul etapei de stabilizare activa (Ciclul II). Am lucrat pe core-stability si exercitii cu banda elastica pentru umeri. Fara simptome dureroase.','a2351fcd-9e0c-4ebc-b6fb-2530c9892556','51abc54c-0c2f-4f0a-aead-bdaa9627661e','2026-07-06 10:55:00.000000','51abc54c-0c2f-4f0a-aead-bdaa9627661e','51abc54c-0c2f-4f0a-aead-bdaa9627661e'),(27,'2026-07-08 10:55:00.000000','Echilibru bun la exercitiile pe suprafete instabile. Corectii minime necesare pe alinierea trunchiului.','a2351fcd-9e0c-4ebc-b6fb-2530c9892556','51abc54c-0c2f-4f0a-aead-bdaa9627661e','2026-07-08 10:55:00.000000','51abc54c-0c2f-4f0a-aead-bdaa9627661e','51abc54c-0c2f-4f0a-aead-bdaa9627661e'),(28,'2026-07-10 10:55:00.000000','Toleranta mare la efort. Pacienta efectueaza si acasa planul de intretinere. Postura stabila.','a2351fcd-9e0c-4ebc-b6fb-2530c9892556','51abc54c-0c2f-4f0a-aead-bdaa9627661e','2026-07-10 10:55:00.000000','51abc54c-0c2f-4f0a-aead-bdaa9627661e','51abc54c-0c2f-4f0a-aead-bdaa9627661e'),(29,'2026-07-15 10:55:00.000000','Sedinta 4 finalizata. Obiectivele clinice au fost indeplinite integral. Pacienta este externata cu recomandari clare de mentinere pe termen lung.','a2351fcd-9e0c-4ebc-b6fb-2530c9892556','51abc54c-0c2f-4f0a-aead-bdaa9627661e','2026-07-15 10:55:00.000000','51abc54c-0c2f-4f0a-aead-bdaa9627661e','51abc54c-0c2f-4f0a-aead-bdaa9627661e'),(30,'2026-06-03 09:55:00.000000','Prima sedinta de kinetoterapie pentru lombalgie. Mobilizari blande pe flexie/extensie si exercitii usoare de respiratie. Durere locala declarata la efort.','de85c053-a583-4219-8fe9-5afd66c0e812','d407ab1c-7554-456d-9726-3f5571fa8fd0','2026-06-03 09:55:00.000000','d407ab1c-7554-456d-9726-3f5571fa8fd0','d407ab1c-7554-456d-9726-3f5571fa8fd0'),(31,'2026-06-05 09:55:00.000000','Contractura paravertebrala incepe sa se diminueze. Am inceput tonifierea musculaturii abdominale profunde (transversul abdominal).','de85c053-a583-4219-8fe9-5afd66c0e812','d407ab1c-7554-456d-9726-3f5571fa8fd0','2026-06-05 09:55:00.000000','d407ab1c-7554-456d-9726-3f5571fa8fd0','d407ab1c-7554-456d-9726-3f5571fa8fd0'),(32,'2026-06-08 09:55:00.000000','Pacienta raporteaza ameliorarea semnificativa a simptomelor la birou. Am adaugat exercitii din pozitia patrupedie.','de85c053-a583-4219-8fe9-5afd66c0e812','d407ab1c-7554-456d-9726-3f5571fa8fd0','2026-06-08 09:55:00.000000','d407ab1c-7554-456d-9726-3f5571fa8fd0','d407ab1c-7554-456d-9726-3f5571fa8fd0'),(33,'2026-06-10 09:55:00.000000','Executie buna a exercitiilor de tip \"plank\" adaptate. Rezistenta musculara crescuta pe zona lombara.','de85c053-a583-4219-8fe9-5afd66c0e812','d407ab1c-7554-456d-9726-3f5571fa8fd0','2026-06-10 09:55:00.000000','d407ab1c-7554-456d-9726-3f5571fa8fd0','d407ab1c-7554-456d-9726-3f5571fa8fd0'),(34,'2026-06-12 09:55:00.000000','Fara episoade de durere acuta in ultima saptamana. Lucram intens pe mobilitatea soldurilor si stretching active pe lantul posterior.','de85c053-a583-4219-8fe9-5afd66c0e812','d407ab1c-7554-456d-9726-3f5571fa8fd0','2026-06-12 09:55:00.000000','de85c053-a583-4219-8fe9-5afd66c0e812','de85c053-a583-4219-8fe9-5afd66c0e812'),(35,'2026-06-15 09:55:00.000000','Ultima sedinta din planul initial. Pacienta descrie o stare generala excelenta, avand mobilitate completa si absenta durerilor zilnice.','de85c053-a583-4219-8fe9-5afd66c0e812','d407ab1c-7554-456d-9726-3f5571fa8fd0','2026-06-15 09:55:00.000000','d407ab1c-7554-456d-9726-3f5571fa8fd0','d407ab1c-7554-456d-9726-3f5571fa8fd0'),(36,'2026-07-06 09:55:00.000000','Inceperea sedintelor de gimnastica profilactica (mentinere). Focusul este mentinerea tonusului si constientizarea posturii corecte la birou.','de85c053-a583-4219-8fe9-5afd66c0e812','d407ab1c-7554-456d-9726-3f5571fa8fd0','2026-07-06 09:55:00.000000','d407ab1c-7554-456d-9726-3f5571fa8fd0','d407ab1c-7554-456d-9726-3f5571fa8fd0'),(37,'2026-07-08 09:55:00.000000','Exercitii dinamice executate cu usurinta. Pacienta demonstreaza insusirea corecta a tehnicilor de ridicare a greutatilor din viata cotidiana.','de85c053-a583-4219-8fe9-5afd66c0e812','d407ab1c-7554-456d-9726-3f5571fa8fd0','2026-07-08 09:55:00.000000','de85c053-a583-4219-8fe9-5afd66c0e812','de85c053-a583-4219-8fe9-5afd66c0e812'),(38,'2026-07-10 09:55:00.000000','Stretching intens al musculaturii flexoare de sold si pectorale. Postura globala deschisa, fara cifotizare.','de85c053-a583-4219-8fe9-5afd66c0e812','d407ab1c-7554-456d-9726-3f5571fa8fd0','2026-07-10 09:55:00.000000','de85c053-a583-4219-8fe9-5afd66c0e812','de85c053-a583-4219-8fe9-5afd66c0e812'),(39,'2026-07-13 09:55:00.000000','Ultima sedinta din programul de mentinere. Pacientul relateaza ca se simte excelent, fara dureri. Recomandari de mentinere oferite.','de85c053-a583-4219-8fe9-5afd66c0e812','d407ab1c-7554-456d-9726-3f5571fa8fd0','2026-07-13 09:55:00.000000','de85c053-a583-4219-8fe9-5afd66c0e812','de85c053-a583-4219-8fe9-5afd66c0e812'),(40,'2026-06-02 12:05:00.000000','Prima sedinta post-operatorie. Exercitii foarte usoare in descarcare de greutate pe saltea. Pacienta prezinta rigiditate musculara, dar este foarte cooperanta.','8bd48465-32ec-413b-9985-9a57a03a3d88','05e0f10e-2c4d-405e-abac-5ccedb83d2af','2026-06-02 12:05:00.000000','05e0f10e-2c4d-405e-abac-5ccedb83d2af','05e0f10e-2c4d-405e-abac-5ccedb83d2af'),(41,'2026-06-04 16:05:00.000000','Sedinta desfasurata in Locatia 8. S-au efectuat mobilizari neuro-dinamice pentru nervul sciatic. Durerea iradiata pe picior s-a diminuat considerabil.','8bd48465-32ec-413b-9985-9a57a03a3d88','05e0f10e-2c4d-405e-abac-5ccedb83d2af','2026-06-04 16:05:00.000000','05e0f10e-2c4d-405e-abac-5ccedb83d2af','05e0f10e-2c4d-405e-abac-5ccedb83d2af'),(42,'2026-06-05 16:05:00.000000','Continuam cresterea amplitudinii de miscare in extensie si rotatie. Forta musculara pe cvadriceps si fesieri se imbunatateste treptat.','8bd48465-32ec-413b-9985-9a57a03a3d88','05e0f10e-2c4d-405e-abac-5ccedb83d2af','2026-06-05 16:05:00.000000','05e0f10e-2c4d-405e-abac-5ccedb83d2af','05e0f10e-2c4d-405e-abac-5ccedb83d2af'),(43,'2026-06-08 12:05:00.000000','Ultima sedinta din planul post-operator. Control motor optim pe trunchi. Amplitudinea articulara este sigura si stabile. Pacienta este gata pentru reevaluare.','8bd48465-32ec-413b-9985-9a57a03a3d88','05e0f10e-2c4d-405e-abac-5ccedb83d2af','2026-06-08 12:05:00.000000','05e0f10e-2c4d-405e-abac-5ccedb83d2af','05e0f10e-2c4d-405e-abac-5ccedb83d2af'),(44,'2026-07-08 11:55:00.000000','Pacienta a revenit in programul meu pentru faza de stabilizare activa. Am initiat exercitii specifice de tip core-stability si exercitii pe placa de echilibru.','8bd48465-32ec-413b-9985-9a57a03a3d88','51abc54c-0c2f-